        self.graph_file = self.storage_path / "graph.pkl"
        self.metadata_file = self.storage_path / "metadata.json"

    def save(self, graph: nx.Graph) -> bool:
        """保存知识图谱到磁盘

        Args:
            graph: 知识图谱对象

        Returns:
