            else:
                print("知识图谱文件不存在，创建新的知识图谱")
                return nx.Graph()
        except Exception as e:
            print(f"加载知识图谱失败: {e}")
            return nx.Graph()

    def exists(self) -> bool:
        """检查知识图谱文件是否存在

        Returns:
