"""
Notion 读取器 - 通过 Notion API 读取内容
"""
from pathlib import Path
from typing import List, Dict, Any, Optional
from datetime import datetime

from core.file_reader import BaseFileReader, FileContent
from config import CHUNK_SIZE, CHUNK_OVERLAP, NOTION_API_KEY, NOTION_DATABASE_ID


class NotionReader(BaseFileReader):
    """Notion API 读取器"""

    def __init__(self, api_key: str = None):
        super().__init__()
        self.api_key = api_key or NOTION_API_KEY
        self.client = None

        if self.api_key:
            try:
                from notion_client import Client
                self.client = Client(auth=self.api_key)
            except Exception as e:
                print(f"Notion 客户端初始化失败: {e}")

    def read(self, file_path: Path = None, page_id: str = None, database_id: str = None) -> FileContent:
        """
        读取 Notion 页面或数据库

        Args:
            file_path: 不使用，保持接口一致
            page_id: Notion 页面 ID
            database_id: Notion 数据库 ID
        """
        if not self.client:
            raise ValueError("Notion API Key 未配置")

        if page_id:
            return self._read_page(page_id)
        elif database_id:
            return self._read_database(database_id)
        elif NOTION_DATABASE_ID:
            return self._read_database(NOTION_DATABASE_ID)
        else:
            raise ValueError("需要提供 page_id 或 database_id")

    def _read_page(self, page_id: str) -> FileContent:
        """读取单个页面"""
        # 获取页面信息
        page = self.client.pages.retrieve(page_id=page_id)

        # 获取页面标题
        title = self._extract_title(page)

        # 获取页面内容
        blocks = self._get_all_blocks(page_id)
        content = self._blocks_to_text(blocks)

        # 元数据
        metadata = {
            "page_id": page_id,
            "object": page.get('object'),
            "created_time": page.get('created_time'),
            "last_edited_time": page.get('last_edited_time'),
            "url": page.get('url'),
        }

        # 分块
        chunks = self.chunk_content(content, CHUNK_SIZE, CHUNK_OVERLAP)

        return FileContent(
            source=f"notion://{page_id}",
            content=content,
            file_type="notion",
            title=title,
            metadata=metadata,
            chunks=chunks,
            file_hash=self.calculate_hash(content)
        )

    def _read_database(self, database_id: str) -> List[FileContent]:
        """读取数据库中的所有页面"""
        results = []

        # 查询数据库
        pages = self.client.databases.query(database_id=database_id)

        for page in pages.get('results', []):
            page_id = page.get('id')
            try:
                content = self._read_page(page_id)
                results.append(content)
            except Exception as e:
                print(f"读取页面失败 {page_id}: {e}")

        return results

    def _get_all_blocks(self, block_id: str) -> List[Dict]:
        """获取所有块（包括嵌套）"""
        blocks = []
        cursor = None

        while True:
            response = self.client.blocks.children.list(
                block_id=block_id,
                start_cursor=cursor
            )

            for block in response.get('results', []):
                blocks.append(block)

                # 递归获取嵌套块
                if block.get('has_children'):
                    nested_blocks = self._get_all_blocks(block.get('id'))
                    block['children'] = nested_blocks

            if not response.get('has_more'):
                break
            cursor = response.get('next_cursor')

        return blocks

    def _blocks_to_text(self, blocks: List[Dict], depth: int = 0) -> str:
        """将块转换为文本"""
        texts = []
        indent = "  " * depth

        for block in blocks:
            block_type = block.get('type')
            block_data = block.get(block_type, {})

            text = self._extract_text_from_rich_text(block_data.get('rich_text', []))

            if block_type == 'paragraph':
                if text:
                    texts.append(f"{indent}{text}")

            elif block_type == 'heading_1':
                texts.append(f"{indent}# {text}")
            elif block_type == 'heading_2':
                texts.append(f"{indent}## {text}")
            elif block_type == 'heading_3':
                texts.append(f"{indent}### {text}")

            elif block_type == 'bulleted_list_item':
                texts.append(f"{indent}- {text}")
            elif block_type == 'numbered_list_item':
                texts.append(f"{indent}1. {text}")

            elif block_type == 'to_do':
                checked = "[x]" if block_data.get('checked') else "[ ]"
                texts.append(f"{indent}- {checked} {text}")

            elif block_type == 'code':
                language = block_data.get('language', '')
                texts.append(f"{indent}```{language}\n{text}\n{indent}```")

            elif block_type == 'quote':
                texts.append(f"{indent}> {text}")

            elif block_type == 'divider':
                texts.append(f"{indent}---")

            elif block_type == 'image':
                caption = self._extract_text_from_rich_text(block_data.get('caption', []))
                texts.append(f"{indent}[图片: {caption}]")

            # 处理子块
            if 'children' in block:
                child_text = self._blocks_to_text(block['children'], depth + 1)
                if child_text:
                    texts.append(child_text)

        return "\n".join(texts)

    def _extract_text_from_rich_text(self, rich_text: List[Dict]) -> str:
        """从 rich_text 中提取纯文本"""
        return "".join([t.get('plain_text', '') for t in rich_text])

    def _extract_title(self, page: Dict) -> str:
        """提取页面标题"""
        properties = page.get('properties', {})

        # 查找标题属性
        for prop_name, prop_data in properties.items():
            if prop_data.get('type') == 'title':
                title_items = prop_data.get('title', [])
                return "".join([t.get('plain_text', '') for t in title_items])

        return "Untitled"

    def list_databases(self) -> List[Dict]:
        """列出所有可访问的数据库"""
        if not self.client:
            return []

        try:
            response = self.client.search(
                filter={"value": "database", "property": "object"}
            )
            return response.get('results', [])
        except Exception as e:
            print(f"列出数据库失败: {e}")
            return []

    def list_pages(self, database_id: str = None) -> List[Dict]:
        """列出页面"""
        if not self.client:
            return []

        try:
            if database_id:
                response = self.client.databases.query(database_id=database_id)
            else:
                response = self.client.search(
                    filter={"value": "page", "property": "object"}
                )
            return response.get('results', [])
        except Exception as e:
            print(f"列出页面失败: {e}")
            return []

"""
Obsidian 读取器 - 读取 Obsidian 知识库
"""
from pathlib import Path
from typing import List, Dict, Any, Generator
import json

from core.file_reader import BaseFileReader, FileContent
from readers.text_reader import MarkdownReader
from config import CHUNK_SIZE, CHUNK_OVERLAP, OBSIDIAN_VAULT_PATH


class ObsidianReader:
    """Obsidian 知识库读取器"""

    def __init__(self, vault_path: str = None):
        self.vault_path = Path(vault_path) if vault_path else None
        if not self.vault_path and OBSIDIAN_VAULT_PATH:
            self.vault_path = Path(OBSIDIAN_VAULT_PATH)

        self.markdown_reader = MarkdownReader()

    def read_vault(self, include_attachments: bool = False) -> Generator[FileContent, None, None]:
        """
        读取整个 Obsidian 知识库

        Args:
            include_attachments: 是否包含附件（图片、PDF等）
        """
        if not self.vault_path or not self.vault_path.exists():
            raise ValueError(f"Obsidian 知识库路径无效: {self.vault_path}")

        # 遍历所有 Markdown 文件
        for md_file in self.vault_path.rglob("*.md"):
            # 跳过隐藏文件夹（如 .obsidian）
            if any(part.startswith('.') for part in md_file.relative_to(self.vault_path).parts):
                continue

            try:
                content = self.markdown_reader.read(md_file)
                # 添加 Obsidian 特定元数据
                content.metadata['vault_path'] = str(self.vault_path)
                content.metadata['relative_path'] = str(md_file.relative_to(self.vault_path))
                content.file_type = "obsidian"
                content.source = f"obsidian://{md_file.relative_to(self.vault_path)}"
                yield content
            except Exception as e:
                print(f"读取文件失败 {md_file}: {e}")

    def read_file(self, relative_path: str) -> FileContent:
        """读取单个文件"""
        if not self.vault_path:
            raise ValueError("Obsidian 知识库路径未配置")

        file_path = self.vault_path / relative_path
        if not file_path.exists():
            raise FileNotFoundError(f"文件不存在: {file_path}")

        content = self.markdown_reader.read(file_path)
        content.metadata['vault_path'] = str(self.vault_path)
        content.metadata['relative_path'] = relative_path
        content.file_type = "obsidian"
        content.source = f"obsidian://{relative_path}"

        return content

    def get_all_notes(self) -> List[Dict[str, Any]]:
        """获取所有笔记的列表"""
        if not self.vault_path or not self.vault_path.exists():
            return []

        notes = []
        for md_file in self.vault_path.rglob("*.md"):
            if any(part.startswith('.') for part in md_file.relative_to(self.vault_path).parts):
                continue

            relative_path = str(md_file.relative_to(self.vault_path))
            stat = md_file.stat()

            notes.append({
                "path": relative_path,
                "name": md_file.stem,
                "size": stat.st_size,
                "modified": stat.st_mtime,
            })

        return notes

    def get_graph_data(self) -> Dict[str, Any]:
        """
        获取知识图谱数据（节点和链接）
        """
        nodes = []
        links = []
        node_map = {}

        for note in self.get_all_notes():
            note_path = note['path']
            node_id = len(nodes)
            node_map[note_path] = node_id
            nodes.append({
                "id": node_id,
                "path": note_path,
                "name": note['name'],
            })

        # 查找链接
        for md_file in self.vault_path.rglob("*.md"):
            if any(part.startswith('.') for part in md_file.relative_to(self.vault_path).parts):
                continue

            relative_path = str(md_file.relative_to(self.vault_path))
            source_id = node_map.get(relative_path)

            if source_id is None:
                continue

            try:
                with open(md_file, 'r', encoding='utf-8', errors='ignore') as f:
                    content = f.read()

                # 查找 Wiki 链接 [[...]]
                import re
                wiki_links = re.findall(r'\[\[([^\]|]+)(?:\|[^\]]*)?\]\]', content)

                for link in wiki_links:
                    # 处理链接（可能包含别名）
                    link_path = link.strip()

                    # 查找目标节点
                    for note_path, target_id in node_map.items():
                        if link_path in note_path or note_path.endswith(f"{link_path}.md"):
                            links.append({
                                "source": source_id,
                                "target": target_id,
                            })
                            break

            except Exception as e:
                print(f"解析链接失败 {md_file}: {e}")

        return {
            "nodes": nodes,
            "links": links,
        }

    def search_in_vault(self, query: str) -> List[Dict[str, Any]]:
        """在知识库中搜索"""
        results = []
        query_lower = query.lower()

        for md_file in self.vault_path.rglob("*.md"):
            if any(part.startswith('.') for part in md_file.relative_to(self.vault_path).parts):
                continue

            try:
                with open(md_file, 'r', encoding='utf-8', errors='ignore') as f:
                    content = f.read()

                if query_lower in content.lower():
                    # 找到匹配的上下文
                    lines = content.split('\n')
                    matching_lines = []

                    for i, line in enumerate(lines):
                        if query_lower in line.lower():
                            # 获取上下文
                            start = max(0, i - 2)
                            end = min(len(lines), i + 3)
                            context = '\n'.join(lines[start:end])
                            matching_lines.append({
                                "line_number": i + 1,
                                "context": context,
                            })

                    results.append({
                        "path": str(md_file.relative_to(self.vault_path)),
                        "name": md_file.stem,
                        "matches": matching_lines[:5],  # 限制匹配数量
                    })

            except Exception as e:
                print(f"搜索失败 {md_file}: {e}")

        return results

    def get_tags(self) -> Dict[str, List[str]]:
        """获取所有标签及其对应的文件"""
        tags = {}

        for md_file in self.vault_path.rglob("*.md"):
            if any(part.startswith('.') for part in md_file.relative_to(self.vault_path).parts):
                continue

            try:
                with open(md_file, 'r', encoding='utf-8', errors='ignore') as f:
                    content = f.read()

                # 查找标签 #tag
                import re
                file_tags = re.findall(r'#([a-zA-Z0-9_\-\u4e00-\u9fff]+)', content)

                relative_path = str(md_file.relative_to(self.vault_path))

                for tag in file_tags:
                    if tag not in tags:
                        tags[tag] = []
                    tags[tag].append(relative_path)

            except Exception as e:
                print(f"解析标签失败 {md_file}: {e}")

        return tags

